   226→  async function handleSearch(query: string) {
   227→    if (!query.trim()) {
   228→      fetchData();
   229→      return;
   230→    }
   231→
   232→    const res = await fetch(
   233→      `/api/map/search?q=${encodeURIComponent(query)}`
   234→    );
   235→    if (res.ok) {
   236→      const results = await res.json() as MapNode[];
   237→      setNodes(results);
   238→      setEdges([]);
   239→    }
   240→  }
   241→
   242→  if (loading) {
   243→    return (
   244→      <div className="h-screen flex items-center justify-center">
   245→        <div className="text-center">
   246→          <div className="text-4xl mb-3 animate-spin">🧭</div>
   247→          <p className="text-[#6B7280] text-sm">Loading your map...</p>
   248→        </div>
   249→      </div>
   250→    );
   251→  }
   252→
   253→  if (nodes.length === 0) {
   254→    return (
   255→      <div className="h-screen flex items-center justify-center bg-gradient-to-br from-[#F2F4F7] to-[#E8EBF0]">
   256→        <div className="text-center max-w-sm px-6">
   257→          <div className="text-5xl mb-4">🗺️</div>
   258→          <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
   259→            Map is being built
   260→          </h2>
   261→          <p className="text-sm text-[#6B7280] mb-4">
   262→            The career and education map will populate as you complete
   263→            reflections and build your signal profile. Check back after your
   264→            first reflection!
   265→          </p>
   266→          <a
   267→            href="/reflect"
   268→            className="inline-block px-5 py-2.5 bg-[#3B82F6] text-white rounded-xl text-sm font-medium hover:bg-[#2563EB] transition-colors"
   269→          >
   270→            Start a Reflection
   271→          </a>
   272→        </div>
   273→      </div>
   274→    );
   275→  }
   276→
   277→  return (
   278→    <div className="relative w-full h-screen overflow-hidden bg-gradient-to-br from-[#F2F4F7] to-[#E8EBF0]">
   279→      {/* Controls */}
   280→      <div className="absolute top-4 left-4 right-4 z-20 flex items-start gap-3">
   281→        <MapSearchBar onSearch={handleSearch} />
   282→
   283→        <button
   284→          onClick={() => setPersonalized(!personalized)}
   285→          className={`flex-shrink-0 px-4 py-2.5 rounded-xl text-sm font-medium glass-card transition-all ${
   286→            personalized
   287→              ? "text-[#3B82F6] border-blue-200/60"
   288→              : "text-[#6B7280]"
   289→          }`}
   290→        >
   291→          {personalized ? "✨ Personalized" : "All Nodes"}
   292→        </button>
   293→      </div>
   294→
   295→      {/* D3 Canvas */}
   296→      <svg ref={svgRef} className="w-full h-full" />
   297→
   298→      {/* Legend */}
   299→      <div className="absolute bottom-24 left-4 z-20">
   300→        <MapLegend />
   301→      </div>
   302→
   303→      {/* Node Detail Panel */}
   304→      {selectedNode && (
   305→        <MapNodeDetail
   306→          node={selectedNode}
   307→          onClose={() => setSelectedNode(null)}
   308→        />
   309→      )}
   310→    </div>
   311→  );
   312→}
